import{_ as i,o as a,c as l,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"形式化验证（安全模型）","description":"","frontmatter":{"permalink":"/security/formal-verification/","summary":"针对 OpenSoul 最高风险路径的机器检查安全模型。","title":"形式化验证（安全模型）","x-i18n":{"generated_at":"2026-02-03T07:54:04Z","model":"claude-opus-4-5","provider":"pi","source_hash":"8dff6ea41a37fb6b870424e4e788015c3f8a6099075eece5dbf909883c045106","source_path":"security/formal-verification.md","workflow":15}},"headers":[],"relativePath":"zh-CN/security/formal-verification.md","filePath":"zh-CN/security/formal-verification.md","lastUpdated":null}'),n={name:"zh-CN/security/formal-verification.md"};function o(r,e,t,d,p,c){return a(),l("div",null,[...e[0]||(e[0]=[s(`<h1 id="形式化验证-安全模型" tabindex="-1"><a class="header-anchor" href="#形式化验证-安全模型">#</a> 形式化验证（安全模型）</h1><p>本页跟踪 OpenSoul 的<strong>形式化安全模型</strong>（目前是 TLA+/TLC；根据需要会添加更多）。</p><blockquote><p>注意：一些较旧的链接可能引用了以前的项目名称。</p></blockquote><p><strong>目标（北极星）：</strong> 提供机器检查的论证，证明 OpenSoul 在明确假设下执行其 预期的安全策略（授权、会话隔离、工具门控和 配置错误安全）。</p><p><strong>目前是什么：</strong> 一个可执行的、攻击者驱动的<strong>安全回归测试套件</strong>：</p><ul><li>每个声明都有一个在有限状态空间上运行的模型检查。</li><li>许多声明有一个配对的<strong>负面模型</strong>，为现实的 bug 类别生成反例追踪。</li></ul><p><strong>目前还不是什么：</strong> 证明&quot;OpenSoul 在所有方面都是安全的&quot;或完整 TypeScript 实现是正确的。</p><h2 id="模型存放位置" tabindex="-1"><a class="header-anchor" href="#模型存放位置">#</a> 模型存放位置</h2><p>模型维护在一个单独的仓库中：<a href="https://github.com/vignesh07/opensoul-formal-models" target="_blank" rel="noreferrer">vignesh07/opensoul-formal-models</a>。</p><h2 id="重要注意事项" tabindex="-1"><a class="header-anchor" href="#重要注意事项">#</a> 重要注意事项</h2><ul><li>这些是<strong>模型</strong>，不是完整的 TypeScript 实现。模型和代码之间可能存在偏差。</li><li>结果受 TLC 探索的状态空间限制；&quot;绿色&quot;并不意味着在建模的假设和边界之外也是安全的。</li><li>一些声明依赖于明确的环境假设（例如，正确的部署、正确的配置输入）。</li></ul><h2 id="复现结果" tabindex="-1"><a class="header-anchor" href="#复现结果">#</a> 复现结果</h2><p>目前，结果通过在本地克隆模型仓库并运行 TLC 来复现（见下文）。未来的迭代可能提供：</p><ul><li>带有公开产物（反例追踪、运行日志）的 CI 运行模型</li><li>用于小型、有界检查的托管&quot;运行此模型&quot;工作流</li></ul><p>开始使用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/vignesh07/opensoul-formal-models</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul-formal-models</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 需要 Java 11+（TLC 在 JVM 上运行）。</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 仓库内置了固定版本的 \`tla2tools.jar\`（TLA+ 工具）并提供 \`bin/tlc\` + Make 目标。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">targe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="gateway-网关暴露和开放-gateway-网关配置错误" tabindex="-1"><a class="header-anchor" href="#gateway-网关暴露和开放-gateway-网关配置错误">#</a> Gateway 网关暴露和开放 Gateway 网关配置错误</h3><p><strong>声明：</strong> 在没有认证的情况下绑定到 loopback 之外可能使远程入侵成为可能 / 增加暴露；令牌/密码可以阻止未认证的攻击者（根据模型假设）。</p><ul><li>绿色运行： <ul><li><code>make gateway-exposure-v2</code></li><li><code>make gateway-exposure-v2-protected</code></li></ul></li><li>红色（预期）： <ul><li><code>make gateway-exposure-v2-negative</code></li></ul></li></ul><p>另见：模型仓库中的 <code>docs/gateway-exposure-matrix.md</code>。</p><h3 id="nodes-run-管道-最高风险能力" tabindex="-1"><a class="header-anchor" href="#nodes-run-管道-最高风险能力">#</a> Nodes.run 管道（最高风险能力）</h3><p><strong>声明：</strong> <code>nodes.run</code> 需要（a）节点命令允许列表加上声明的命令以及（b）配置时的实时批准；批准被令牌化以防止重放（在模型中）。</p><ul><li>绿色运行： <ul><li><code>make nodes-pipeline</code></li><li><code>make approvals-token</code></li></ul></li><li>红色（预期）： <ul><li><code>make nodes-pipeline-negative</code></li><li><code>make approvals-token-negative</code></li></ul></li></ul><h3 id="配对存储-私信门控" tabindex="-1"><a class="header-anchor" href="#配对存储-私信门控">#</a> 配对存储（私信门控）</h3><p><strong>声明：</strong> 配对请求遵守 TTL 和待处理请求上限。</p><ul><li>绿色运行： <ul><li><code>make pairing</code></li><li><code>make pairing-cap</code></li></ul></li><li>红色（预期）： <ul><li><code>make pairing-negative</code></li><li><code>make pairing-cap-negative</code></li></ul></li></ul><h3 id="入站门控-提及-控制命令绕过" tabindex="-1"><a class="header-anchor" href="#入站门控-提及-控制命令绕过">#</a> 入站门控（提及 + 控制命令绕过）</h3><p><strong>声明：</strong> 在需要提及的群组上下文中，未授权的&quot;控制命令&quot;不能绕过提及门控。</p><ul><li>绿色： <ul><li><code>make ingress-gating</code></li></ul></li><li>红色（预期）： <ul><li><code>make ingress-gating-negative</code></li></ul></li></ul><h3 id="路由-会话键隔离" tabindex="-1"><a class="header-anchor" href="#路由-会话键隔离">#</a> 路由/会话键隔离</h3><p><strong>声明：</strong> 来自不同对等方的私信不会折叠到同一会话中，除非明确链接/配置。</p><ul><li>绿色： <ul><li><code>make routing-isolation</code></li></ul></li><li>红色（预期）： <ul><li><code>make routing-isolation-negative</code></li></ul></li></ul><h2 id="v1-额外的有界模型-并发、重试、追踪正确性" tabindex="-1"><a class="header-anchor" href="#v1-额外的有界模型-并发、重试、追踪正确性">#</a> v1++：额外的有界模型（并发、重试、追踪正确性）</h2><p>这些是后续模型，围绕真实世界的故障模式（非原子更新、重试和消息扇出）提高保真度。</p><h3 id="配对存储并发-幂等性" tabindex="-1"><a class="header-anchor" href="#配对存储并发-幂等性">#</a> 配对存储并发 / 幂等性</h3><p><strong>声明：</strong> 配对存储应该在交错情况下也强制执行 <code>MaxPending</code> 和幂等性（即&quot;检查然后写入&quot;必须是原子/加锁的；刷新不应创建重复项）。</p><p>这意味着：</p><ul><li><p>在并发请求下，你不能超过渠道的 <code>MaxPending</code>。</p></li><li><p>对同一 <code>(channel, sender)</code> 的重复请求/刷新不应创建重复的活跃待处理行。</p></li><li><p>绿色运行：</p><ul><li><code>make pairing-race</code>（原子/加锁的上限检查）</li><li><code>make pairing-idempotency</code></li><li><code>make pairing-refresh</code></li><li><code>make pairing-refresh-race</code></li></ul></li><li><p>红色（预期）：</p><ul><li><code>make pairing-race-negative</code>（非原子 begin/commit 上限竞争）</li><li><code>make pairing-idempotency-negative</code></li><li><code>make pairing-refresh-negative</code></li><li><code>make pairing-refresh-race-negative</code></li></ul></li></ul><h3 id="入站追踪关联-幂等性" tabindex="-1"><a class="header-anchor" href="#入站追踪关联-幂等性">#</a> 入站追踪关联 / 幂等性</h3><p><strong>声明：</strong> 摄入应在扇出过程中保持追踪关联，并在提供商重试下保持幂等。</p><p>这意味着：</p><ul><li><p>当一个外部事件变成多个内部消息时，每个部分都保持相同的追踪/事件标识。</p></li><li><p>重试不会导致重复处理。</p></li><li><p>如果提供商事件 ID 缺失，去重回退到安全键（例如，追踪 ID）以避免丢弃不同的事件。</p></li><li><p>绿色：</p><ul><li><code>make ingress-trace</code></li><li><code>make ingress-trace2</code></li><li><code>make ingress-idempotency</code></li><li><code>make ingress-dedupe-fallback</code></li></ul></li><li><p>红色（预期）：</p><ul><li><code>make ingress-trace-negative</code></li><li><code>make ingress-trace2-negative</code></li><li><code>make ingress-idempotency-negative</code></li><li><code>make ingress-dedupe-fallback-negative</code></li></ul></li></ul><h3 id="路由-dmscope-优先级-identitylinks" tabindex="-1"><a class="header-anchor" href="#路由-dmscope-优先级-identitylinks">#</a> 路由 dmScope 优先级 + identityLinks</h3><p><strong>声明：</strong> 路由必须默认保持私信会话隔离，只有在明确配置时才折叠会话（渠道优先级 + 身份链接）。</p><p>这意味着：</p><ul><li><p>渠道特定的 dmScope 覆盖必须优先于全局默认值。</p></li><li><p>identityLinks 应该只在明确链接的组内折叠，而不是跨不相关的对等方。</p></li><li><p>绿色：</p><ul><li><code>make routing-precedence</code></li><li><code>make routing-identitylinks</code></li></ul></li><li><p>红色（预期）：</p><ul><li><code>make routing-precedence-negative</code></li><li><code>make routing-identitylinks-negative</code></li></ul></li></ul>`,46)])])}const g=i(n,[["render",o]]);export{u as __pageData,g as default};
